VALUES
  ('social-worker-moex-05990', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據志願服務法規定，下列敘述何者正確？', '["本法所定志工的義務包括可接受服務對象報酬", "中央主管機關應至少每五年舉辦志願服務調查研究，並出版統計報告", "主管機關及各目的事業主管機關每半年至少應召開志願服務聯繫會報一次", "民防、義勇警察、義勇交通警察等人員其服務年資滿三年，服務時數達三百小時以上者，進入公立風 景區得以免費"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05991', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據社會工作師法有關時間的規定，下列敘述何者正確？', '["社會工作師執行業務時，應撰製社會工作紀錄，紀錄保存年限不得少於六年", "社會工作師及專科社會工作師執業，應接受繼續教育，並每五年提出完成繼續教育證明文件，辦理執 業執照更新", "申請設立社會工作師事務所之社會工作師，須執行第十二條所訂之業務七年以上，並得有工作證明者， 始得為之", "社會工作師事務所停業、歇業或其登記事項變更時，應自事實發生之日起三十日內，報請原發開業執 照機關備查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05992', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'essay', '青少年對性別角色的態度不僅影響個人本身日後的工作及家庭生活，更影響臺灣社
會之性別平等和性別關係之發展。請詳述，青少年在型塑其性別角色態度過程中，
受到那些因素之影響？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05993', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'essay', '對於婚姻關係良好的夫妻而言，喪偶本身即是個人生命史中重大的失落經驗，因而
容易出現極大的悲傷情緒。請詳述，悲傷情緒對喪偶者可能引發的負面影響為何？
並且進一步說明悲傷輔導的重點？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05994', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '當社會工作者將「種族」視為健康評估的一個項目時，下列何者是錯誤的思維？', '["社會工作者在進行健康評估時，應假設個案的「種族」是導致某些疾病主要的風險因素", "不同「種族」會有不同的健康結果，可能來自於種族隔離、不當對待少數種族等因素所形成的", "社會工作者在以「種族」差異，解釋不同健康結果時，應謹慎說明並透過實證調查取得客觀證據", "許多不同種族的個案，他們有不同的獲取健康促進行為的方式與機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05995', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關青少年期「親子間依附關係」的討論，何者錯誤？', '["與父母有安全依附關係的青少年，通常比較獨立、自信心較高、發展也比較順利", "不同族群或社經地位的青少年，和父母都有安全的依附關係，但對他們身心發展所產生的影響，卻是 不同的", "穩固與安全的依附關係，就如同對嬰幼兒，有助於青少年的健全發展", "心理分析學派認為青少年應降低與父母之間的安全依附關係，這將有助於青少年完成獨立的發展任務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05996', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「寄養青少年」的敘述，何者錯誤？', '["針對年長的青少年，寄養服務應該是「選擇性的」而不是「唯一的」安置方式", "社會工作者在提供寄養服務時，應先瞭解青少年對自我價值、寄養經驗的看法", "低自尊的寄養青少年，和其寄養時間長短、寄養經驗等因素有關係，這些都和他們後續學校適應問題 與行為問題具有高度相關", "多次寄養安置的選擇，才能讓青少年找到最合適的寄養家庭"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05997', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關Erikson社會心理理論（心理社會發展階段）的敘述，何者錯誤？', '["每個發展階段，都有一種特定的心理社會危機或衝突", "他將每個人的心理社會發展階段分為九個階段，第一個階段為嬰幼兒期，發展任務與危機為「信任與 不信任」", "每個發展階段都有個體需要面對的生理、情緒和認知等各種任務，以便適應社會環境的需求", "主張人類的發展必須遵循固定的階段"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05998', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童中期（6～12歲）開始發展「性別的刻板印象」（sex-role stereotypes），下列敘述何者錯誤？', '["兒童中期開始意識到性別角色的差異，兒童會將周遭重要他人對性別角色的期待，融入在自我的概念中", "學校與家庭是形塑兒童性別刻板印象的主要場所", "性別迷思很難改變，因為對於性別角色的刻板印象，是從年紀很小的時候就根植在心中", "只要透過家庭成員及學校老師的不斷教育，兒童中期的孩子是可以立即改變性別刻板印象的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05999', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「老年人應該在許多社會角色上，繼續保持活躍，主觀的幸福感則會愈強」，這是下列那個理論的主要 論述？', '["活動理論", "撤退理論", "持續理論", "超越理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
